#!/usr/bin/env python3
import re
import sys

src, dst = sys.argv[1], sys.argv[2]
tokens = re.findall(r"^\s*CT_([A-Z0-9_]+),", open(src).read(), re.MULTILINE)

with open(dst, "w") as f:
    f.write("/* Generated by gen_token_names.py */\n")
    f.write("#ifndef TOKEN_NAMES_H_INCLUDED\n")
    f.write("#define TOKEN_NAMES_H_INCLUDED\n\n")
    f.write("const char *token_names[] =\n{\n")
    for t in tokens:
        f.write(f'   "{t}",\n')
    f.write("};\n\n")
    f.write("#endif /* TOKEN_NAMES_H_INCLUDED */\n")
